import React from 'react';
import { Home, FileText, History, Zap, ShieldCheck, LogOut } from 'lucide-react';

const Navbar = ({ activeTab, setActiveTab, isAdmin, onLogout }) => {
  return (
    <nav className="sticky top-0 z-50 glass border-b border-gray-800 no-print">
      <div className="container mx-auto px-4">
        <div className="flex items-center justify-between h-20">
          <div
            className="flex items-center gap-2 cursor-pointer"
            onClick={() => setActiveTab('home')}
          >
            <div className="bg-yellow-500 p-2 rounded-lg">
              <Zap className="text-black" size={24} fill="currentColor" />
            </div>
            <span className="text-2xl font-bold gold-text-gradient tracking-tighter">
              MULANI ELECTRICALS
            </span>
          </div>

          <div className="hidden md:flex items-center gap-6">
            <button
              onClick={() => setActiveTab('home')}
              className={`flex items-center gap-2 font-medium transition-colors ${activeTab === 'home' ? 'text-yellow-500' : 'text-gray-400 hover:text-white'}`}
            >
              <Home size={18} /> Home
            </button>
            <button
              onClick={() => setActiveTab('billing')}
              className={`flex items-center gap-2 font-medium transition-colors ${activeTab === 'billing' ? 'text-yellow-500' : 'text-gray-400 hover:text-white'}`}
            >
              <FileText size={18} /> New Bill
            </button>
            <button
              onClick={() => setActiveTab('history')}
              className={`flex items-center gap-2 font-medium transition-colors ${activeTab === 'history' ? 'text-yellow-500' : 'text-gray-400 hover:text-white'}`}
            >
              <History size={18} /> Records
            </button>

            {isAdmin && (
              <button
                onClick={() => setActiveTab('admin')}
                className={`flex items-center gap-2 font-medium transition-colors ${activeTab === 'admin' ? 'text-yellow-500' : 'text-gray-400 hover:text-white'}`}
              >
                <ShieldCheck size={18} /> Manage Home
              </button>
            )}

            {isAdmin ? (
               <button
                onClick={onLogout}
                className="flex items-center gap-2 font-medium text-red-400 hover:text-red-300 transition-colors ml-4"
              >
                <LogOut size={18} /> Logout
              </button>
            ) : (
              <button
                onClick={() => setActiveTab('login')}
                className={`flex items-center gap-2 font-medium transition-colors ${activeTab === 'login' ? 'text-yellow-500' : 'text-gray-400 hover:text-white'} ml-4`}
              >
                <ShieldCheck size={18} /> Admin
              </button>
            )}
          </div>

          {/* Mobile Menu */}
          <div className="md:hidden flex gap-4">
            <button onClick={() => setActiveTab('billing')} className="text-yellow-500">
              <FileText size={24} />
            </button>
            <button onClick={() => setActiveTab('history')} className="text-gray-400">
              <History size={24} />
            </button>
            {isAdmin && (
               <button onClick={() => setActiveTab('admin')} className="text-blue-400">
                <ShieldCheck size={24} />
              </button>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
